import java.util.ArrayList;import java.util.LinkedHashMap;import java.util.List;import java.util.Map;
final class MementoPattern{static final class PatternException extends RuntimeException{private final String code;PatternException(String c){super(c);code=c;}String code(){return code;}}record Memento(String primary,List<String>fallbacks){Memento{fallbacks=List.copyOf(fallbacks);}}
static final class RouteConfig{String primary;List<String>fallbacks;RouteConfig(Map<String,Object>v){primary=String.valueOf(v.get("primary"));fallbacks=new ArrayList<>((List<String>)v.getOrDefault("fallbacks",List.of()));}Memento snapshot(){return new Memento(primary,fallbacks);}void restore(Memento m){primary=m.primary();fallbacks=new ArrayList<>(m.fallbacks());}Map<String,Object>value(){Map<String,Object>out=new LinkedHashMap<>();out.put("primary",primary);out.put("fallbacks",new ArrayList<>(fallbacks));return out;}}
@SuppressWarnings("unchecked")static Object evaluate(Map<String,Object>input){RouteConfig config=new RouteConfig((Map<String,Object>)input.get("initial"));List<Memento>snapshots=new ArrayList<>();List<String>audit=new ArrayList<>();for(Map<String,Object>op:(List<Map<String,Object>>)input.getOrDefault("operations",List.of())){switch(String.valueOf(op.get("op"))){case"snapshot"-> {snapshots.add(config.snapshot());audit.add("snapshot:"+(snapshots.size()-1));}case"set_primary"->{config.primary=String.valueOf(op.get("value"));audit.add("set_primary:"+config.primary);}case"append_fallback"->{String value=String.valueOf(op.get("value"));config.fallbacks.add(value);audit.add("append_fallback:"+value);}case"restore"->{int index=((Number)op.get("index")).intValue();if(index<0||index>=snapshots.size())throw new PatternException("unknown_memento");config.restore(snapshots.get(index));audit.add("restore:"+index);}default->throw new PatternException("unsupported_operation");}}return Map.of("config",config.value(),"snapshots",snapshots.size(),"audit",audit);}}
